@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>
</div>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNow" disabled="@(!hasUnsavedChanges)">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private bool hasUnsavedChanges;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeyTimestamp = "notepad-timestamp";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", $"./{Components.App.AssemblyName}.lib.module.js");

            var stored = await module.InvokeAsync<string?>("getItem", StorageKeyContent);
            var storedTime = await module.InvokeAsync<string?>("getItem", StorageKeyTimestamp);

            if (!string.IsNullOrEmpty(stored))
            {
                content = stored;
                savedContent = stored;
            }

            if (!string.IsNullOrEmpty(storedTime) && DateTime.TryParse(storedTime, out var parsed))
            {
                lastSavedAt = parsed;
            }

            autoSaveTimer = new System.Threading.Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
            StateHasChanged();
        }
    }

    private void OnContentChanged()
    {
        hasUnsavedChanges = content != savedContent;
        _ = SetBeforeUnload(hasUnsavedChanges);
    }

    private async Task SetBeforeUnload(bool enabled)
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", enabled);
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        if (!hasUnsavedChanges) return;

        await InvokeAsync(async () =>
        {
            await Save();
            StateHasChanged();
        });
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is null) return;

        savedContent = content;
        lastSavedAt = DateTime.Now;
        hasUnsavedChanges = false;

        await module.InvokeVoidAsync("setItem", StorageKeyContent, content);
        await module.InvokeVoidAsync("setItem", StorageKeyTimestamp, lastSavedAt.Value.ToString("O"));
        await SetBeforeUnload(false);
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        hasUnsavedChanges = false;

        if (module is not null)
        {
            await module.InvokeVoidAsync("removeItem", StorageKeyContent);
            await module.InvokeVoidAsync("removeItem", StorageKeyTimestamp);
            await SetBeforeUnload(false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", false);
            await module.DisposeAsync();
        }
    }
}

